def rob(nums):
    n = len(nums)
    if n == 0:
        return 0
    if n == 1:
        return nums[0]
    best = 0
    for mask in range(1 << n):
        total = 0
        valid = True
        for i in range(n):
            if mask & (1 << i):
                total += nums[i]
                if mask & (1 << ((i + 1) % n)):
                    valid = False
                    break
        if valid:
            best = max(best, total)
    return best

def rob(nums):
    n = len(nums)
    if n == 0:
        return 0
    if n == 1:
        return nums[0]

    def rob_linear(houses):
        prev, curr = 0, 0
        for x in houses:
            prev, curr = curr, max(curr, prev + x)
        return curr

    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))
